script.text:
      &ScriptVoucherInit;

function init$Voucher$(f) {initialize(f, 'ong_ba', 'ma_gd', 'loai_ct', 'status');&InitFormDetailTax;}
function active$Voucher$(f) {&ScriptActiveVoucher;
  if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  &EISetFieldsReadOnly;&EISetFormButtonEdit;&CancelStatusDefault;&LoadFormDetailTax;&VoucherLogHandleStatus;
  &ListCreate;
  &PostCreate;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;
  if (f._action == 'Edit') f._customerIdentity = f.getItemValue('ma_kh');
  &EISetFieldsReadOnly;&EISetFormButtonEdit;&CancelStatusDefault;&VoucherLogHandleStatus;
}
function close$Voucher$(f) {&ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d25')._controlBehavior;
  switch (action) {
    case 'Save':
      f.getItem('ma_kh2').field.AllowNulls = (f.getItemValue('thue_cn') == 0);
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      break;
    case 'Explore':
    &CancelStatusExplore;
    &VoucherLogHandleStatusExplore;
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d25')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_tien_nt2,t_thue_nt,t_tt_nt:t_tien2,t_thue,t_tt');

    var $dt = {};
    $dt.aGridFields = 'gia_nt2,tien_nt2:gia2,tien2';
    $dt.aTotalFields = [['t_tien_nt2', 'tien_nt2'], ['t_tien2', 'tien2']];
    &DetailTaxCurrencyCreate;

    v.addGridFields(g, $dt.aGridFields);
    v.addTotalFields(g, $dt.aTotalFields);
    v.set_referenceFields(null);
    v.set_executeExpression($dt.aExpression);

&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {
    if (e.object._baseCurrency == e.type) {
      var c = &DetailTaxFormTabFocus;;
      var a = [['d25', c]], f = sender.get_element().parentForm;
      focus$Voucher$Tab(f, a);
      &PostCurrencySelected;
    }
  }
}
function onChange$Voucher$Tab(sender, e) {
  var a = ['d25'];
  focus$Voucher$Tab(sender.parentForm, a);
  &PostTabFocus;
}
function focus$Voucher$Tab(f, a) {
  if (f._usedEI) Array.add(a, 'sd_hddt_yn');
  &ListTabChange;
  &PostTabChange;
  Array.add(a, 'ma_nvbh');
  f.focusWhenTabChanged(a);
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Voucher$DebitAccount(o) {o.parentForm.request('DebitAccount', 'DebitAccount', ['tk'], o);}
function onChange$Voucher$TaxCode(o) {o.parentForm.request('GetTaxRate', 'GetTaxRate', ['ma_thue', 'loai_ct'], o);}
function onChange$Voucher$TaxAccount(o) {o.parentForm.request('TaxAccount', 'TaxAccount', ['tk_thue'], o);}
function onChange$Voucher$ForeignCurrencyTaxAmount(e) {
  var f = e.parentForm, o = f.getItem('t_thue');
  f.executeExpression(['[t_thue]:=[t_thue_nt]*[ty_gia]', '[t_tt_nt]:=[t_tien_nt2]+[t_thue_nt]', '[t_tt]:=[t_tien2]+[t_thue]']);
  f.live(o);
}
function onChange$Voucher$BaseCurrencyTaxAmount(e) {e.parentForm.executeExpression(['[t_tt]:=[t_tien2]+[t_thue]']);}
function onChange$Voucher$Transaction(o) {o.parentForm.request('Transaction', 'Transaction', ['ma_gd', 'ma_thue'], o);}
/* </flatten> */


function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      set$Voucher$DefaultValue(f);
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      set$Voucher$DefaultValue(f);
      break;

      &VoucherNumberReading;
      &CurrencyResponse;

    case 'Customer':
      f.setItemControlBehavior('tk', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('tk_thue_no', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('ma_tt', result[2].Value, result[3].Value, &ResetCustInfoFields;);
      f.setItemControlBehavior('ten_khthue', result[4].Value, null, true);
      f.setItemControlBehavior('ong_ba', result[5].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('dia_chithue', result[6].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('ma_so_thue', result[7].Value, null, &ResetCustInfoFields;);
      f.setItemControlBehavior('ma_nvbh', result[8].Value, result[9].Value, &ResetCustInfoFields;);
      &EICustomerResponseComplete;
      f.live(f.getItem('ong_ba'));
      break;
    case 'DebitAccount':
      f.setItemControlBehavior('tk_thue_no', result[0].Value, '');
      break;
    case 'GetTaxRate':
      var r = result[0].Value;
      if (f.getItemValue('thue_suat') != r) {
        f.setItemValue('thue_suat', r);
        f.executeExpression(['[t_thue_nt]:=[t_tien_nt2]*[thue_suat]/100', '[t_thue]:=[t_tien2]*[thue_suat]/100', '[t_tt_nt]:=[t_tien_nt2]+[t_thue_nt]', '[t_tt]:=[t_tien2]+[t_thue]']);
      }
      f.setItemControlBehavior('tk_thue', result[1].Value, '', true);
      f.setItemValue('thue_cn', result[2].Value);
      break;
    case 'TaxAccount':
      f.setItemValue('thue_cn', result[0].Value);
      break;
    case 'Transaction':
      f.setItemControlBehavior('loai_ct', result[0].Value, null, true);
      &DetailTaxResponseCompleteTransaction;
      var v = (result[0].Value == '2');
      onChange$Voucher$TransactionType(f, v);
      break;
    &EIResponseCompleteChecking;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function onChange$Voucher$TransactionType(f, v, start) {
  var g = f.getItem("d25")._controlBehavior;
  var c0 = g._getColumnOrder('tk_du'), c1 = g._getColumnOrder('tk_dt'), c2 = g._getColumnOrder('tk_gghb');
  var n1 = g._getColumnOrder('kieu_dt'), n2 = g._getColumnOrder('kieu_gg');
  var r = start ? start : 1;
  for (var i = r; i <= g._rowCount; i++) {
    var o = g._getItem(i, c0);
    o.row = i;
    var s = g._getItemValue(i, v ? c1 : c2), t = g._getItemValue(i, v ? n1 : n2);
    if (s) g.setItemGridBehavior(o, [['tk_du', s, ['', t], true]]);
  }
}
/* </flatten> */
function set$Voucher$DefaultValue(f) {
  &DetailTaxFormDefaultValue;
}
/* <flatten type="Javascript"> */
function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if (o.a) $common.setVisible(o.a, !v);
    o.disabled = v;
  }
}
function setFieldsEmpty(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    if(!v) o.value = '';
  }
}
/* </flatten> */
function when$VoucherCopying(f) {f.setItemValue('stt_rec', '');&DetailTaxVoucherCopying;}

