&CommandSetVoucherNumber;
if exists(select 1 from dmkh where ma_kh = @ma_kh and (kh_yn = 1 or nv_yn = 1)) begin &EICustomerResponseExists; select rtrim(a.tk) as tk, b.ten_tk%l, rtrim(a.ma_tt) as ma_tt, c.ten_tt%l, rtrim(a.ten_kh) as ten_kh, rtrim(doi_tac) as ong_ba, rtrim(a.dia_chi) as dia_chi, rtrim(a.ma_so_thue) as ma_so_thue, rtrim(a.ma_nvbh) as ma_nvbh, d.ten_nvbh%l&EICustomerResponseValue; from dmkh a left join dmtk b on a.tk = b.tk left join dmtt c on a.ma_tt = c.ma_tt left join dmnvbh d on a.ma_nvbh = d.ma_nvbh where a.ma_kh = @ma_kh return end
if exists(select 1 from dmtk where tk = @tk and loai_tk = 1) begin select @tk as value return end
if exists(select 1 from dmtk where tk = @tk_thue and loai_tk = 1) begin select tk_cn from dmtk where tk = @tk_thue return end
declare @voucherType varchar(2) select @voucherType = rtrim(loai_ct) from dmmagd where ma_ct = 'HD4' and ma_gd = @ma_gd if '&DetailTaxFlag;' <> '1' and exists(select 1 from dmthue where ma_thue = @ma_thue) if @voucherType = '2' begin select @voucherType as loai_ct, rtrim(a.tk_thue_co) as tk_thue, isnull(b.tk_cn, 0) as thue_cn from dmthue a left join dmtk b on a.tk_thue_co = b.tk where a.ma_thue = @ma_thue end else begin select @voucherType as loai_ct, rtrim(a.tk_thue_no) as tk_thue, isnull(b.tk_cn, 0) as thue_cn from dmthue a left join dmtk b on a.tk_thue_no = b.tk where a.ma_thue = @ma_thue end else select @voucherType as loai_ct, '' as tk_thue, 0 as thue_cn return
&XMLGetVoucherNumber; &XMLGetExchangeRate;
if exists(select 1 from dmthue where ma_thue = @ma_thue) begin if @loai_ct = '2' begin select a.thue_suat, rtrim(a.tk_thue_co) as tk_thue, isnull(b.tk_cn, 0) as thue_cn from dmthue a left join dmtk b on a.tk_thue_co = b.tk where a.ma_thue = @ma_thue end else begin select a.thue_suat, rtrim(a.tk_thue_no) as tk_thue, isnull(b.tk_cn, 0) as thue_cn from dmthue a left join dmtk b on a.tk_thue_no = b.tk where a.ma_thue = @ma_thue end return end
&ListTicket;
